mapper.select:
SELECT 
FROM jst_participant
WHERE guardian_mobile = #{guardianMobile}
  AND name = #{name}
  AND claim_status = 'unclaimed'
  AND del_flag = '0'

select from jst_participant p left join jst_user u on u.user_id = p.claimed_user_id and u.del_flag = '0' where p.create_by = #{createBy} and p.del_flag = '0'
and case when p.claim_status = 'unclaimed' then 'unclaimed' when p.claim_status = 'pending_manual' then 'conflict' else 'claimed' end = #{status}
order by p.create_time desc, p.participant_id desc

select 
from jst_participant
where participant_id = #{participantId}
  and create_by = #{createBy}
  and del_flag = '0'
limit 1

