    #{participantType}, #{name}, #{gender}, #{age}, #{school}, #{className},
    #{guardianMobile}, #{guardianName},
    #{claimStatus}, #{visibleScope}, #{createBy}, #{createTime}, #{updateBy}, #{updateTime}
